window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2005>1","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"inadequate food production in most developing countries is due to","images":[],"options":{"A":"high population growth","B":"inadequate technology","C":"infestation of farms by pest","D":"scarcity of labour"},"answer":"B","explanation":"Inadequate technology is a factor a problem affecting production of agricultural produce in the country.If there is adequate technology there will be adequate food production for the society but for every problem there must be a solution.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>2","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"Which of the following group of basic amenities should be provided in rural areas for improved agricultural productivity?","images":[],"options":{"A":"water, electricity and health care centres","B":"electricity, guest houses and water","C":"health care centres, water and airport","D":"Roads, airport and recreation centers."},"answer":"A","explanation":"The provision of basic amenities such as water, electricity, and health care centres in rural areas can significantly improve agricultural productivity. Access to clean water is essential for both crop irrigation and livestock rearing. Electricity can power machinery and equipment that can increase the efficiency of farming practices. Health care centres can provide medical services to rural populations, ensuring that they are healthy and able to work on their farms. The other options, such as guest houses, airports, and recreation centers, while beneficial in some ways, are not as directly linked to agricultural productivity.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>3","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"BASIC CONCEPTS : AGRICULTURAL LAWS AND REFORMS","question":"Government laws and reforms are aimed at","images":[],"options":{"A":"increasing agriculture production","B":"controlling farm profits","C":"discouraging investment in agriculture","D":"encouraging importation of agriculture produce"},"answer":"A","explanation":"Government laws and reforms in the agricultural sector are primarily aimed at increasing agricultural production. This can be achieved through a variety of means, such as providing subsidies to farmers, implementing policies that encourage sustainable farming practices, and investing in agricultural research and development. While controlling farm profits, discouraging investment in agriculture, and encouraging the importation of agricultural produce may be the effects of certain policies, they are not the primary aim of government laws and reforms.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>4","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"In order to ensure that crop and animals disease are not transferred across international boundaries, government must","images":[],"options":{"A":"have programmes on agricultural education","B":"endeavours to produce only disease resistance species","C":"have and enforce quarantine service","D":"increase survelliance of its border by security agents"},"answer":"C","explanation":"To prevent the transfer of crop and animal diseases across international boundaries, governments must have and enforce quarantine services. Quarantine is a restriction on the movement of people and goods which is intended to prevent the spread of disease or pests. It is often used in connection to disease and illness, preventing the movement of those who may have been exposed to a communicable disease, but do not have a confirmed medical diagnosis.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2005>5","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"The role of science and technology in the development of agriculture includes the following except","images":[],"options":{"A":"provision of insecticides and drugs","B":"provision of good road network","C":"introduction of artificial insemination centers","D":"setting up produce marketing board"},"answer":"B","explanation":"The provision of a good road network is not a direct role of science and technology in the development of agriculture. While good road networks are important for the transportation of agricultural goods, they are not a product of agricultural science and technology. The other options, such as the provision of insecticides and drugs, the introduction of artificial insemination centers, and setting up produce marketing boards, are all direct applications of science and technology in agriculture.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>6","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"The total land area of a country available for farming depends on the","images":[],"options":{"A":"level of literacy of farmers","B":"climate of the area","C":"sex distribution","D":"number of houses and other structures"},"answer":"D","explanation":"The total land area of a country available for farming depends on the number of houses and other structures. This is because these structures occupy land that could otherwise be used for farming. The other options, such as the level of literacy of farmers, the climate of the area, and sex distribution, do not directly determine the total land area available for farming.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>7","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"The scarcity of land often compels peasant farmers to practise","images":[],"options":{"A":"deforestation","B":"selective exploitation","C":"taungya system","D":"afforestation"},"answer":"C","explanation":"Taungya system is defined as the planting of arable crops at early stages of forest establishment and the arable crops are harvested before the trees form canopies.It also compell peasant farmers to scarcity use of land.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>8","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"In west Africa , a greater part of the land is used for","images":[],"options":{"A":"livestock farming","B":"arable cropping","C":"building houses","D":"game reserve"},"answer":"B","explanation":"In West Africa, a greater part of the land is used for arable cropping. Arable cropping refers to growing crops on arable land, which is land capable of being ploughed and used to grow crops. This is due to the region's climate and soil which are suitable for growing a variety of crops such as yam, cassava, maize, millet, sorghum, rice, and groundnut.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>9","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A piece of land can be considered more suitable for livestock production than for crop production when it is","images":[],"options":{"A":"moderately marshy","B":"stony","C":"fertile","D":"infested with weeds"},"answer":"B","explanation":"A piece of land can be considered more suitable for livestock production than for crop production when it is stony. Stony land is not ideal for crop production as it can hinder the growth of plant roots and make ploughing difficult. However, it can be used for livestock production as animals can graze around the stones.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>10","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"The first vegetation zone which runs across the coast of most west Africa countries is the","images":[],"options":{"A":"derived savanna","B":"mangrove forest","C":"guinea savanna","D":"rain forest"},"answer":"B","explanation":"Mangroove forest is a vegetation zone which runs across the coast of fall woody trees, have maining aerated roots, its water is a combination of fresh and salt water.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>11","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"The most active agent of physical weathering in arid regions is","images":[],"options":{"A":"wind","B":"water","C":"temperature","D":"ice"},"answer":"A","explanation":"The most active agent of physical weathering in arid regions is wind. In arid regions, where there is little vegetation to protect the soil and rocks from the wind, it can cause significant erosion and weathering. This process is known as deflation, where wind blows and removes the small particles of soil and rock, leaving behind larger particles and rocks.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>12","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"soil in forest areas would normally have","images":[],"options":{"A":"low moisture content","B":"high proportion of sand","C":"high proportion of humus","D":"low microbial activity"},"answer":"C","explanation":"A high proportion of humus in forest is a mixture of sand and clay particle with high organic matter. The forest soil is more fertile than any other soil.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>13","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"clay particles hold cations becaused they","images":[],"options":{"A":"negatively charged","B":"become hardened when dry","C":"are very small in size","D":"have definite"},"answer":"A","explanation":"Clay soil are fine,powdery and smooth when dry. The particles are sticky and mouldy when wet.The particles are sticky and mouldy when wet.The particles are highly bound together with little pore (air) spaces. It is poorly aerated with high water holding capacity.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>14","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"Under which of the following conditions will organic matter in the soil decomposed fastest?","images":[],"options":{"A":"optimum pH","B":"low temperature","C":"anaerobic condition","D":"waterlogged condition"},"answer":"A","explanation":"Organic matter in the soil decomposes fastest under optimum pH conditions. The pH level of soil affects the activity of the microorganisms that break down organic matter. If the pH is too high or too low, it can inhibit these microorganisms, slowing down the decomposition process. Therefore, optimum pH conditions would allow for the fastest decomposition of organic matter.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>15","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"which of the following materials can be applied to soil in order to correct yellowing of leaves?","images":[],"options":{"A":"lime","B":"urea","C":"Gypsum","D":"bone meal"},"answer":"B","explanation":"Yellowing of leaves is a symptoms of plant diseases which may affect crop production that is why Urea is applied to the soil in order to correct yellowing of leaves.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>16","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"one importance of cover crops is that they","images":[],"options":{"A":"provide shade for crops","B":"protect crops from pest","C":"increase soil acidity","D":"suppress weed growth"},"answer":"D","explanation":"Cover crops are crops that suppress weed growth, provide shade for crops and increase soil acidity but the most importatnt is that it suppress weed growth.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>17","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"The appropiate irrigation method for upland rice field is","images":[],"options":{"A":"sprinkler","B":"drip","C":"flooding","D":"underground"},"answer":"C","explanation":"Flooding is the appropriate irrigation method for upland rice fields. This is because rice plants require a lot of water, and flooding the fields ensures that they get the amount they need. Sprinkler, drip, and underground irrigation methods are not typically used for rice fields because they do not provide the necessary amount of water.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>18","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Drainage refers to","images":[],"options":{"A":"removal of excess water from the soil","B":"removal of nutrient from the soil","C":"addition of water to the soil","D":"protection of soil from erosion"},"answer":"A","explanation":"Drainage is a process whereby excess water in the soil is removed artifically to promote good farming activities.It is also the withdrawal of excess water from the soil while at the same here retaining adequate resences.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>19","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"Energy in fossil material may be harnessed as","images":[],"options":{"A":"water energy","B":"wind energy","C":"electrical energy","D":"fuel energy"},"answer":"D","explanation":"Fuel energy is a type of energy in which fossil materials are harvested to produced energy.It is also an energy which is always reliable for agricultural production. Energy in fossil materials maybe harnessed as fuel energy.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>20","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"A decorticator is useful in the processing of","images":[],"options":{"A":"maize","B":"cotton","C":"cocoa","D":"groundnut"},"answer":"B","explanation":"A decorticator is a machine for stripping the skin, bark, or rind off nuts, wood, plant stalks, grain, etc., in preparation for further processing. In the context of agriculture, it is commonly used in the processing of cotton to separate the cotton fibers from their seeds.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>21","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"Which of the following types of survey reveals the pyhsical features of farmlands","images":[],"options":{"A":"soil survey","B":"topography survey","C":"chain survey","D":"compass survey"},"answer":"B","explanation":"Topography survey determines the location of farm building and structures.Farm buildings or living quarters are usually located on high elevations for proper viewing of the farm.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>22","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM PLANNING","question":"calculate the area of a rectangular vegetable garden measuring 100m by 26m in hectares","images":[],"options":{"A":"0.250","B":"0.200","C":"0.125","D":"0.004"},"answer":"A","explanation":"It should be noted that 1 square metre is equilvalent to 0.0001 hectare.  The area of the land given is = 100m \u22c6 26m =2600square metre which is equilvalent to 0.26 hectares","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>23","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PROSPECTS OF AGRICULTURAL MECHANIZATION","question":"farm mechanization does not","images":[],"options":{"A":"involve the use of motorized equipment","B":"require much capital","C":"lead to unemployement","D":"involve the use of only heavy machinery"},"answer":"D","explanation":"Farm mechanization is the application of engineering principles and technology in agricultural production, storage and processing on the farm.It is also the applicable to land preparation,planting,fertilizer application, weeding and crop harvesting e.t.c.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>24","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The prolong wet season at the early stage of growth in cotton will lead to","images":[],"options":{"A":"A good vegetative growth and high yield of lint","B":"tall plant with few bolls","C":"premature dropping of leaves","D":"waterlogged soil wich increases availabilty of soil nutrients"},"answer":"B","explanation":"A prolonged wet season at the early stage of growth in cotton will lead to tall plants with few bolls. This is because the excess water can lead to excessive vegetative growth at the expense of reproductive growth, resulting in fewer bolls.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>25","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The by-product in plant photosynthesis is","images":[],"options":{"A":"carbon dioxide","B":"carbonhydrates","C":"hydrogen","D":"oxygen"},"answer":"D","explanation":"Photosynthesis is the process in which green plant manufacture their non-food through the use of sunlight.Its by-product is oxygen which is very essential in the nitrogen cycle, carbon cycle.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>26","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the folowing reasons explain why fetilizers are added to soils?","images":[],"options":{"A":"prevention of erosion","B":"increasing organic matter content","C":"increasing water retention capacity","D":"increasing the nutrient level"},"answer":"D","explanation":"Fertilizers are element applied to the soil to enable it to be more fertile and increase the nutrient level of the soil. It is also added to the soil to promote good agricultural production.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>27","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"A crop which is usually propagated sexually is","images":[],"options":{"A":"banana","B":"pineapple","C":"cowpea","D":"ginger"},"answer":"C","explanation":"Cowpea(Vigna unguiculata) is a member of the pulses or legumes.It is rich in protein and is commonly fed on by man.It is usually propagated by sexually by seeds.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>28","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"transplanting is best carried out in the evening because","images":[],"options":{"A":"it allows greater plan respiration","B":"roots show positive geotropism","C":"moisture losses are low during cold weather","D":"plants grow faster in the dark"},"answer":"C","explanation":"Transplanting is the transfer of seedling from nursery beds to their permanent position in the field.The tools used for transplanting are handtrowel,digger,hoe or cutlass. It is done in the evening because moisture losses are low during cold weather.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>29","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Some cassava tubers are poisonous to non-ruminant because they contain","images":[],"options":{"A":"Hydrochloric acid","B":"hydrocyanic acid","C":"sodium chloride","D":"sodium hydroxide"},"answer":"B","explanation":"Cassava tubers contain hydrocyanic acid which are poisonous to non-niminant animals like pig,poultry birds, e.t.c. It can cause diseases in the animal or even sudden death to the animal.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>30","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"Which of the following factor does not affect the distribution of pasture grasses?","images":[],"options":{"A":"wind","B":"temperature","C":"soil","D":"pest"},"answer":"A","explanation":"Wind does not affect the distribution of pasture grasses. The distribution of pasture grasses is primarily determined by factors such as soil type, temperature, and the presence of pests or diseases. While wind can play a role in the dispersal of grass seeds, it does not directly affect the distribution of established grasses.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>31","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"selective exploitation means felling of","images":[],"options":{"A":"different ages and girths","B":"specific ages and girth","C":"different girth and same species.","D":"different girth and different species"},"answer":"B","explanation":"Selective exploitation is the process of selling trees of specific ages and grirths that is specific mature trees in the forest.The system allows for the harvesting of older trees while younger ones remain as cover to the surface of the forest.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>32","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"streak disease of crops commonly attack","images":[],"options":{"A":"millet","B":"sorghum","C":"maize","D":"rice"},"answer":"C","explanation":"Maize is a member of the grass family.It is a cereal crop which produces grains that can be used by food for humans and livestock. It diseases include, Corn smut,maize rust,leaf spot,maize streak. etc","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>33","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"most viral disease of plants are transmitted by","images":[],"options":{"A":"wind","B":"rain","C":"insects","D":"rodents"},"answer":"C","explanation":"Viral diseases are mainly transmitted by insects. Its diseases include;Foot and mouth disease,Rinderpest disease,Newcastle diseases and so on.It affect animals include:cattle,sheep,goat and it controls are vaccination, proper sanitation etc.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>34","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"viral disease of crops plants are best controlled by","images":[],"options":{"A":"planting resistance varieties","B":"applying fungicides","C":"applying insecticides","D":"flooding farmlands"},"answer":"A","explanation":"Viral diseases are controlled by the following ways;Regular vaccination,Proper sanitation, planting resistant varieties, Disinfection of poultry buildings,burning and burying of infected birds.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>35","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"The following problems are likely to be caused by insects except","images":[],"options":{"A":"loss of leaves of crops","B":"rottening of crops in storage","C":"transmission of viral diseases","D":"reduction of grains in storage to powder"},"answer":"B","explanation":"Insects affects crops production by eating leaves of crop plant, transmission of viral diseases, reduction of grains in storage to powder.Insects do not affect the rottening of cobs in storage.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>36","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"weed plants which grow on other plants without deriving nutrients from them are called","images":[],"options":{"A":"sedge","B":"epiphytes","C":"decomposers","D":"saprophytes"},"answer":"B","explanation":"Weed plants which grow on other plants without deriving nutrients from them are called epiphytes. Epiphytes are plants that grow on other plants, but unlike parasites, they do not derive nutrients from their hosts. They only use the host plants for physical support. Sedge is a type of grass-like plant, decomposers are organisms that break down dead or decaying organisms, and saprophytes are organisms that feed on decaying organic matter.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>37","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"When a farmland is heavily infested with shiga, it may be concluded that the farmland","images":[],"options":{"A":"is undergoing drainage","B":"had not been regularly irrigated","C":"may have been used for growing guniea corn","D":"may have been used for cowpea production"},"answer":"D","explanation":"Shiga is a pest that is known to infest cowpea plants. Therefore, if a farmland is heavily infested with shiga, it can be concluded that the farmland may have been used for cowpea production.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>38","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"mulching","images":[],"options":{"A":"reduces evaporation of soil water","B":"increases soil acidity","C":"prevent seedling diseases","D":"improves soil texture"},"answer":"A","explanation":"Mulching is the covering of heaps or ridges with dry leaves to reduce soil temperature, condense soil moisture and prevents rottening of some crop plants, e.g yam setts.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>39","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"An accessory sex gland in bull is","images":[],"options":{"A":"prostrate gland","B":"pituitary gland","C":"thyroid gland","D":"pancreatic gland"},"answer":"A","explanation":"In male mammals, the prostate gland is an accessory sex gland that contributes fluid to the ejaculate. The prostate gland is not unique to bulls but is found in all male mammals.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>40","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"The most important reason for the low livestock population in the rain forest zone is the","images":[],"options":{"A":"fast rate at which pasture crops become fibrous","B":"storage of forage crops during the long dry season","C":"growth and proliferation of pathogen","D":"Thick vegetation cover wich impedes animals movement"},"answer":"C","explanation":"Livestock population in the rainforest zone is low because growth and proliferation of pathogens are factors the affect the livestock population which will affect the agricultural production of animals.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>41","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Which of the following feedstuff does not contain phosphorous?","images":[],"options":{"A":"blood meal","B":"limestone","C":"fish meal","D":"oyster shell"},"answer":"D","explanation":"Oyster shell does not contain phosphorous. Phosphorous is an essential mineral for animals, it is found in many feedstuffs including blood meal, limestone, and fish meal. However, oyster shell is primarily composed of calcium carbonate and does not contain significant amounts of phosphorous.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>42","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"When an animal eats wood and licks iron railing instead of the diet given to it, it is likely that the","images":[],"options":{"A":"animal is on heat","B":"ambient temperature is too high","C":"diet is deficient in essential elements","D":"animal has a pathological disease problems"},"answer":"C","explanation":"An animals that each wood and licks iron railing that animal diet is deficient in essential elements, this will affect the productivity of the animal thus making the animals body system to be weak.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>43","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A indication that chicks are comfortable in a brooder is that they","images":[],"options":{"A":"move away from the source of heat","B":"pant and sit with their mouths open","C":"spread themselves uniformly under the hover","D":"huddle together"},"answer":"C","explanation":"Chicks are the young ones of hens they are always comfortable in their brooders where they are kept and an indication that the chicks are comfortable is that they spread themselves uniformly under the hover.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>44","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"mastitis is disease which affects the","images":[],"options":{"A":"scrotum","B":"udder","C":"dewlap","D":"hump"},"answer":"B","explanation":"Udder which is the mammary gland is a large and succulent organ surrounded by the skin.It is attached to the body of the animal by strong ligament.It is affected by a disease called Mastitis.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>45","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The following are signs of ill-health in farm animals except","images":[],"options":{"A":"watery faeces","B":"bright eyes","C":"loss of appetite","D":"nasal discharge"},"answer":"B","explanation":"Signs of ill health is a symptoms is which farm animals show when they are not alright.They include,watery faeces, loss of appetite, nasal discharge and so on bright eyes is not apart.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>46","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"A protozoon organism causes","images":[],"options":{"A":"coccidiosis","B":"anthrax","C":"rinderpest","D":"aspergillosis"},"answer":"A","explanation":"Coccidiosis is a diseases caused by protozoan and its affects animals like domestic fowl,turkey,duck,goose,rabbit. It symptoms loss of appetities etc. Its control are practice proper sanitation and so on.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>47","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"An animal infected by trypanosomiasis usually develops","images":[],"options":{"A":"bloat and diarhoea","B":"sore legs and running nose","C":"anaemia and swollen lymph gland","D":"swollen legs and constipation"},"answer":"C","explanation":"Trypanomiasis is caused by a protozoan called typanosoma spp.If affects resistant breeds of cattle N'dama,Muhun,Keteku and so on. It symptoms are anaemia,swollen lymph gland, loss of appetite, loss of weight e.t.c","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>48","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The purpose of vaccination is to .....","images":[],"options":{"A":"treat parasite infestation","B":"prevent disease infestation","C":"control parasites","D":"treate disease"},"answer":"B","explanation":"Vaccination is the act in which livestock animal are given medication in case of any diseases or micro organism causing diseases affects the animals.It also helps to prevent disease infection.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>49","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following livestock endoparasite is a hermaphrodite?","images":[],"options":{"A":"liverfluke","B":"trypanosome","C":"tapeworm","D":"roundworm"},"answer":"C","explanation":"Tapeworms are hermaphrodites, meaning they have both male and female reproductive organs. This allows them to self-fertilize and produce eggs without needing a mate. Liver flukes, trypanosomes, and roundworms are not hermaphrodites.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>50","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The most effective method of controlling ectoparasites in farm animals is by regular","images":[],"options":{"A":"exposure of animals to sunlight","B":"dipping of animals in a solution of pesticides","C":"handpicking of ectoparasites","D":"isolation animals"},"answer":"B","explanation":"Ectoparasites includes Ticks,lice and other insects.The most effecting method of controlling this ectoparasites in farm animals is by regular dipping of animals in a solution of pesticides for protection.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>51","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"A common means of aerating a fish pond is stirring the water and","images":[],"options":{"A":"removing dead and decaying matter","B":"adding water plants","C":"adding cold water","D":"pumping oxygen into the water"},"answer":"D","explanation":"A common means of aerating a fish pond is stirring the water and pumping oxygen into the water. This method ensures that the water in the pond is saturated with oxygen, which is essential for the survival of the fish. Removing dead and decaying matter, adding water plants, and adding cold water can also help to improve the quality of the water, but they do not directly aerate the water.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>52","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"using the diagram below to answer question 52 and 53.      The diaram above explains mendel's law of","images":["data:image/png;base64,"],"options":{"A":"segregation of genes","B":"mutation of genes","C":"heterozygosity of genes","D":"homozygosity of genes"},"answer":"A","explanation":"Mendel's law of segregation of genes is also known as Mendel's first law of inheritance. The law states that genes are responsible for the development of the individual and that they are independently transmitted from one generation to another without undergoing any alteration.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>53","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"using the diagram below to answer question 52 and 53.    The components labelled I are the","images":["data:image/png;base64,"],"options":{"A":"gametes","B":"parents","C":"F1 generation","D":"F2 generation"},"answer":"A","explanation":"The components labelled F1 are the gametes. Gametes are specialized reproductive cells that are crucial for sexual reproduction. They carry half the genetic material (haploid) of an organism, which allows for the fusion of genetic material from two parents during fertilization.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>54","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"Heterosis in animal breeding is reffered to as","images":[],"options":{"A":"hybrid vigour","B":"dominance","C":"recessivity","D":"mutation"},"answer":"A","explanation":"Heterosis, also known as hybrid vigour, is a phenomenon in animal and plant breeding where the offspring (hybrid) is superior in certain qualities to both of its parents. It is often used to improve the health, growth rate, or yield of animals or plants.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>55","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"In areas where labour is scarces and land is abundant, farmers tend to","images":[],"options":{"A":"manage dairy animals intensively rather than beef animals","B":"practise mechanized farming","C":"maximize returns on land rather than on labour","D":"employ more hands to work on the land"},"answer":"B","explanation":"Merchandised farming is a type of farming using farm machineries to farm in areas where labour is scarce and land is abundant. The farmers work will be easier and faster because it deals with the use of machines.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>56","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"The supply of farm produce to markets in west africa  is mostly dictated by","images":[],"options":{"A":"government","B":"commodity boards","C":"climatic conditions","D":"the consumers"},"answer":"C","explanation":"The supply of farm produce to markets in West Africa is mostly dictated by climatic conditions. This is because the climate determines the type of crops that can be grown and the time of year they can be harvested. For example, certain crops may only grow during the rainy season, while others may require a dry climate. Therefore, the availability of these crops in the market is largely dependent on the prevailing climatic conditions.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>57","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL INSURANCE","question":"Farm insurance scheme do not cover losses due to","images":[],"options":{"A":"inadequate cultural practices","B":"heavy pest infestation","C":"flood","D":"drought"},"answer":"A","explanation":"Farm insurance schemes typically cover losses due to natural disasters such as floods and droughts, and also losses due to pest infestations. However, they do not cover losses due to inadequate cultural practices. This is because these practices are under the control of the farmer and are not unforeseen events or disasters.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>58","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"The main aim of preparing a farm income and expenditure statement is to","images":[],"options":{"A":"record all purchases","B":"outline the sales of the farm","C":"outline both sales and purchases","D":"calculate profit or loss"},"answer":"D","explanation":"Farm income and expenditure statement is a book used to calculate profit or loss of the total sum of all inputs in the farm.Its helps in making sure the business has a record.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2005>59","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Which marketing agent normally makes the biggest profit margin per unit? the","images":[],"options":{"A":"processor","B":"wholesaler","C":"retailer","D":"commission agent"},"answer":"C","explanation":"The retailer normally makes the biggest profit margin per unit. This is because the retailer is the final link in the supply chain before the product reaches the consumer. The retailer buys the product from the wholesaler at a lower price and then sells it to the consumer at a higher price. The difference between the purchase price and the selling price is the retailer's profit margin.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2005>60","subject":"Agricultural Science","year":"2005","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"The most inappropiate means of disseminating new ideas and techniques to the peasant farmers is by the use of","images":[],"options":{"A":"radio","B":"television","C":"internet","D":"cinema"},"answer":"C","explanation":"The inappropriate means in which peasant farmers disseminate new ideas and techniques is by the use of internet.The internet is an electronic site in which is used for searching about things and so on so peasant farmers should not use the internet.","marks":"1","difficulty":"2"}];